export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

export const parseCurrencyString = (str: string): number => {
  if (!str || typeof str !== 'string') return 0;
  // Remove symbols, dots as thousand separators (common in CO), keep comma as decimal if needed, but usually integers in this dataset
  // Simplified for the typical "$ 147.600" format where dot is thousand separator
  const cleanStr = str.replace(/[$. ]/g, '');
  const num = parseInt(cleanStr, 10);
  return isNaN(num) ? 0 : num;
};

export const formatDate = (dateStr: string) => {
  return dateStr; // Assuming format is already DD/MM/YYYY
};

