import React from 'react';
import { ServiceRecord } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend, CartesianGrid } from 'recharts';
import { formatCurrency } from '../utils';
import { DollarSign, Activity, AlertCircle, TrendingUp } from 'lucide-react';

interface DashboardProps {
  data: ServiceRecord[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  // Calculate Totals
  const totalAdvances = data.reduce((acc, curr) => acc + curr.advanceAmount, 0);
  const totalCases = data.length;
  const uniqueTechnicians = new Set(data.map(d => d.beneficiary)).size;

  // Data for Pie Chart (By Department)
  const deptMap = data.reduce((acc, curr) => {
    acc[curr.department] = (acc[curr.department] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const pieData = Object.keys(deptMap).map(key => ({
    name: key,
    value: deptMap[key]
  }));

  // Data for Bar Chart (By Service Type)
  const serviceMap = data.reduce((acc, curr) => {
    acc[curr.serviceType] = (acc[curr.serviceType] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const barData = Object.keys(serviceMap).map(key => ({
    name: key,
    count: serviceMap[key]
  }));

  const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-start justify-between">
      <div>
        <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon size={24} className="text-white" />
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Anticipos" 
          value={formatCurrency(totalAdvances)} 
          icon={DollarSign} 
          color="bg-blue-500" 
        />
        <StatCard 
          title="Total Casos" 
          value={totalCases} 
          icon={Activity} 
          color="bg-emerald-500" 
        />
        <StatCard 
          title="Técnicos Activos" 
          value={uniqueTechnicians} 
          icon={TrendingUp} 
          color="bg-indigo-500" 
        />
        <StatCard 
          title="Pendientes Revisión" 
          value={data.filter(d => d.status === 'Pending').length} 
          icon={AlertCircle} 
          color="bg-amber-500" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 h-96">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Distribución por Departamento</h3>
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                fill="#8884d8"
                paddingAngle={5}
                dataKey="value"
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip formatter={(value: number) => [value, 'Casos']} />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 h-96">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Casos por Tipo de Servicio</h3>
