import React, { useState, useEffect } from 'react';
import { ServiceRecord } from '../types';
import { formatCurrency } from '../utils';
import { X, Save, Calculator, AlertTriangle } from 'lucide-react';

interface BillingModalProps {
  record: ServiceRecord | null;
  onClose: () => void;
  onSave: (updatedRecord: ServiceRecord) => void;
}

const BillingModal: React.FC<BillingModalProps> = ({ record, onClose, onSave }) => {
  const [formData, setFormData] = useState<ServiceRecord | null>(null);

  useEffect(() => {
    if (record) {
      // Logic: If coming from CSV with empty totals, we might want to pre-fill or keep as is.
      // Here we allow the user to input the values to "Build" the bill.
      setFormData({ ...record });
    }
  }, [record]);

  if (!record || !formData) return null;

  // --- BUSINESS LOGIC: CALCULATION ENGINE ---
  const calculateTotals = () => {
    const income = 
      (formData.valueLabor || 0) +
      (formData.valueAdditionalDay || 0) +
      (formData.valueFailedVisit || 0) +
      (formData.valueCivilWorks || 0) +
      (formData.valueTransport || 0);

    const deductions = 
      (formData.totalAdvances || 0) + // Usually Total Anticipos includes the Advance Amount
      (formData.reteFuente || 0) +
      (formData.reteIca || 0) +
      (formData.otherDiscounts || 0);

    // Logic from CSV: Saldo Labor Técnico seems to be Income - Deductions
    const balance = income - deductions;

    setFormData(prev => {
        if(!prev) return null;
        return {
            ...prev,
            subtotalService: income,
            totalService: income,
            balanceLabor: balance,
            balanceToPay: balance
        }
    });
  };

  const handleInputChange = (field: keyof ServiceRecord, value: string) => {
    const numValue = parseFloat(value) || 0;
    setFormData(prev => {
        if (!prev) return null;
        return { ...prev, [field]: numValue };
    });
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col">

        {/* Header */}
        <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Detalle de Facturación</h2>
            <p className="text-sm text-slate-500">Caso: {formData.caseId} | {formData.beneficiary}</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6">

          {/* Order Details (Read Only) */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8 bg-blue-50 p-4 rounded-lg border border-blue-100">
            <div>
              <label className="text-xs font-semibold text-blue-700 uppercase">Departamento</label>
              <div className="text-sm text-slate-700">{formData.department}</div>
            </div>
            <div>
              <label className="text-xs font-semibold text-blue-700 uppercase">Municipio</label>
              <div className="text-sm text-slate-700">{formData.municipality}</div>
            </div>
            <div>
              <label className="text-xs font-semibold text-blue-700 uppercase">Servicio</label>
              <div className="text-sm text-slate-700 font-medium">{formData.serviceType}</div>
            </div>
             <div className="md:col-span-3 mt-2">
              <label className="text-xs font-semibold text-blue-700 uppercase">Descripción de la Orden</label>
              <div className="text-sm text-slate-700">{formData.orderDescription}</div>
            </div>
          </div>

          {/* Logic Grid: Income vs Deductions */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

            {/* Left: Income / Labor */}
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2 pb-2 border-b border-slate-200">
                <Calculator className="text-emerald-500" size={20} />
                <h3 className="font-bold text-slate-800">Conceptos de Cobro (Ingresos)</h3>
              </div>

              <div className="grid grid-cols-1 gap-4">
                <InputGroup label="Valor Labor (Inst/Mant/Mig)" value={formData.valueLabor} onChange={(v) => handleInputChange('valueLabor', v)} />
                <InputGroup label="Día Adicional" value={formData.valueAdditionalDay} onChange={(v) => handleInputChange('valueAdditionalDay', v)} />
                <InputGroup label="Visita Fallida" value={formData.valueFailedVisit} onChange={(v) => handleInputChange('valueFailedVisit', v)} />
                <InputGroup label="Obras Civiles / Otros" value={formData.valueCivilWorks} onChange={(v) => handleInputChange('valueCivilWorks', v)} />
                <InputGroup label="Transportes / Excedentes" value={formData.valueTransport} onChange={(v) => handleInputChange('valueTransport', v)} />
              </div>

              <div className="flex justify-between items-center pt-4 border-t border-slate-200">
                <span className="font-bold text-slate-700">Subtotal Servicio</span>
                <span className="font-bold text-emerald-600 text-lg">
                  {formatCurrency((formData.valueLabor || 0) + (formData.valueAdditionalDay || 0) + (formData.valueFailedVisit || 0) + (formData.valueCivilWorks || 0) + (formData.valueTransport || 0))}
                </span>
              </div>
            </div>

            {/* Right: Deductions / Discounts */}
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-2 pb-2 border-b border-slate-200">
                <AlertTriangle className="text-amber-500" size={20} />
                <h3 className="font-bold text-slate-800">Deducciones y Anticipos</h3>
              </div>

              <div className="grid grid-cols-1 gap-4">
                 <InputGroup label="Total Anticipos Recibidos" value={formData.totalAdvances} onChange={(v) => handleInputChange('totalAdvances', v)} highlight />
                 <InputGroup label="Retención en la Fuente" value={formData.reteFuente} onChange={(v) => handleInputChange('reteFuente', v)} />
                 <InputGroup label="Rete ICA" value={formData.reteIca} onChange={(v) => handleInputChange('reteIca', v)} />
                 <InputGroup label="Descuentos Parafiscales" value={formData.otherDiscounts} onChange={(v) => handleInputChange('otherDiscounts', v)} />
              </div>

               <div className="bg-amber-50 p-3 rounded text-xs text-amber-800 mt-4">
                Nota: El IVA (19%) se calcula automáticamente si aplica al régimen tributario del técnico.
               </div>
            </div>
          </div>

        </div>

        {/* Footer Actions */}
        <div className="p-6 border-t border-slate-200 bg-slate-50 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <button 
                onClick={calculateTotals}
                className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-medium px-4 py-2 hover:bg-blue-100 rounded-lg transition-colors"
            >
                <Calculator size={18} />
                Recalcular Saldos
            </button>
            <div className="text-right">
                <div className="text-xs text-slate-500 font-semibold uppercase">Saldo a Pagar</div>
                <div className={`text-2xl font-bold ${formData.balanceToPay < 0 ? 'text-red-600' : 'text-blue-600'}`}>
                    {formatCurrency(formData.balanceToPay)}
                </div>
            </div>
          </div>

          <div className="flex gap-3">
            <button onClick={onClose} className="px-5 py-2.5 rounded-lg border border-slate-300 text-slate-700 font-medium hover:bg-white transition-colors">
              Cancelar
            </button>
            <button 
                onClick={() => onSave(formData)}
                className="px-5 py-2.5 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700 shadow-lg shadow-blue-500/30 flex items-center gap-2 transition-transform active:scale-95"
            >
              <Save size={18} />
              Guardar Factura
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// Helper Component for Inputs
const InputGroup = ({ label, value, onChange, highlight }: { label: string, value: number, onChange: (val: string) => void, highlight?: boolean }) => (
    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2">
        <label className={`text-sm ${highlight ? 'font-bold text-slate-800' : 'text-slate-600'}`}>{label}</label>
        <div className="relative w-full sm:w-40">
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">$</span>
            <input 
                type="number" 
                className={`w-full pl-7 pr-3 py-2 border rounded-lg text-right text-sm focus:ring-2 outline-none transition-all ${highlight ? 'border-amber-300 bg-amber-50 focus:ring-amber-500' : 'border-slate-300 focus:ring-blue-500'}`}
                value={value}
                onChange={(e) => onChange(e.target.value)}
                placeholder="0"
            />
        </div>
    </div>
);

export default BillingModal;

