              <CheckCircle size={18} /> Módulo 5: Estado Final
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center">
              <div>
                <div className="text-xs text-slate-400 mb-1">Fórmula:</div>
                <div className="text-xs text-slate-300 italic">Total Servicio + IVA - (ReteFuente + ReteICA + Desc.)</div>
              </div>

              <div className="text-right">
                <div className="text-sm font-medium text-slate-400 uppercase mb-1">Saldo Labor Técnico</div>
                <div className="text-3xl font-bold text-white tracking-tight">{formatCurrency(formData.balanceLabor)}</div>
