// Default empty record for creation
const EMPTY_RECORD: ServiceRecord = {
  id: '',
  caseId: '',
  orderDescription: '',
  serviceType: '',
  department: '',
  municipality: '',
  difficulty: '',
  beneficiary: '',
  date: new Date().toLocaleDateString('es-CO'),
  acta: '',
  valueLabor: 0,
  valueAdditionalDay: 0,
  valueFailedVisit: 0,
  valueCivilWorks: 0,
  valueTransport: 0,
  advanceAmount: 0,
  totalAdvances: 0,
  iva: 0,
  reteFuente: 0,
  reteIca: 0,
  otherDiscounts: 0,
  subtotalService: 0,
  totalService: 0,
  balanceLabor: 0,
  balanceToPay: 0,
  status: 'Abierto',
  observation: ''
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewMode>('dashboard');
  const [data, setData] = useState<ServiceRecord[]>(MOCK_DATA);
  const [selectedRecord, setSelectedRecord] = useState<ServiceRecord | null>(null);
  const [isNewRecord, setIsNewRecord] = useState(false);

  const handleEditRecord = (record: ServiceRecord) => {
    setSelectedRecord(record);
    setIsNewRecord(false);
  };

  const handleCreateRecord = () => {
    // Create a unique ID
    const newId = Math.floor(Math.random() * 100000).toString();
    setSelectedRecord({ ...EMPTY_RECORD, id: newId });
    setIsNewRecord(true);
  };

  const handleSaveRecord = (updatedRecord: ServiceRecord) => {
    if (isNewRecord) {
      setData(prev => [updatedRecord, ...prev]);
    } else {
      setData(prevData => prevData.map(item => item.id === updatedRecord.id ? updatedRecord : item));
    }
    setSelectedRecord(null);
    setIsNewRecord(false);
  };

  return (
    <div className="flex min-h-screen bg-slate-100 font-sans">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />

      <main className="ml-64 flex-1 p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
                {currentView === 'dashboard' ? 'Panel de Control' : 
                 currentView === 'invoices' ? 'Gestión de Facturación' : 'Gestión de Técnicos'}
            </h1>
            <p className="text-slate-500 text-sm mt-1">
              Bienvenido al sistema de liquidación de servicios.
            </p>
          </div>
          <div className="flex items-center gap-4">
             {currentView === 'invoices' && (
               <button 
                onClick={handleCreateRecord}
                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium shadow-md transition-all active:scale-95"
               >
                 <Plus size={20} />
                 Nuevo Servicio
               </button>
             )}
             <div className="flex items-center gap-3 border-l pl-4 border-slate-300">
                <div className="text-right hidden sm:block">
                    <div className="text-sm font-bold text-slate-700">Admin User</div>
                    <div className="text-xs text-slate-400">Coordinador</div>
                </div>
                <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold border border-blue-200">
                    AU
                </div>
             </div>
          </div>
        </header>

        {currentView === 'dashboard' && <Dashboard data={data} />}

        {currentView === 'invoices' && (
          <InvoiceList 
            data={data} 
            onEdit={handleEditRecord} 
          />
        )}

        {currentView === 'technicians' && (
           <div className="bg-white p-12 rounded-xl text-center shadow-sm border border-slate-200">
              <div className="inline-block p-4 rounded-full bg-blue-50 mb-4">
                <svg className="w-12 h-12 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
                </svg>
              </div>
              <h3 className="text-lg font-medium text-slate-900">Módulo en Desarrollo</h3>
              <p className="text-slate-500 mt-2">La vista de consolidado por técnico estará disponible pronto.</p>
           </div>
        )}

      </main>

      {/* Modal is rendered at root level but controlled via state */}
      <BillingModal 
        record={selectedRecord} 
        onClose={() => setSelectedRecord(null)} 
        onSave={handleSaveRecord}
        isNew={isNewRecord}
      />
    </div>
  );
};

