  valueFailedVisit: 0,
  valueCivilWorks: 0,
  valueTransport: 0,
  advanceAmount: 0,
  totalAdvances: 0,
  iva: 0,
  reteFuente: 0,
  reteIca: 0,
  otherDiscounts: 0,
