const isValidUrl = (url: string | null) => {
  if (!url || url.includes('TU_SUPABASE_URL')) return false;
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
};

export const supabase = (isValidUrl(supabaseUrl) && supabaseAnonKey)
  ? createClient(supabaseUrl!, supabaseAnonKey!)
  : null;

