                {/* Logo Image */}
                <img 
                    src="/logo.png" 
                    alt="Panamproject Logo" 
                    className="h-20 w-auto object-contain"
                    onError={(e) => {
                        // Fallback text if image is missing
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
